// Combine all fetched emails into one text block for the AI prompt, tagging each with its Gmail category
const items = $input.all();

if (items.length === 0) {
  return [{ json: { emailBlock: 'No new unread emails in the last 24 hours.', hasEmails: false } }];
}

// Map Gmail's internal category labels to plain-English tags
const categoryMap = {
  CATEGORY_PROMOTIONS: 'Promotions',
  CATEGORY_SOCIAL: 'Social',
  CATEGORY_UPDATES: 'Updates',
  CATEGORY_FORUMS: 'Forums',
  CATEGORY_PERSONAL: 'Primary'
};

function getCategory(json) {
  const labelIds = json.labelIds || json.labelIds_resolved || [];
  if (!Array.isArray(labelIds)) return 'Primary';
  for (const [labelId, name] of Object.entries(categoryMap)) {
    if (labelIds.includes(labelId)) return name;
  }
  return 'Primary';
}

// Gmail node output shape varies by n8n version/Simplify setting - check every known shape,
// falling back to the raw payload.headers array which the Gmail API always includes
function getHeaderValue(json, headerName) {
  const headers = json.payload?.headers || json.headers;
  if (Array.isArray(headers)) {
    const found = headers.find((h) => (h.name || '').toLowerCase() === headerName.toLowerCase());
    if (found && found.value) return found.value;
  }
  return null;
}

function getFrom(json) {
  if (typeof json.from === 'string' && json.from.trim()) return json.from;
  if (json.from?.value?.[0]?.address) return json.from.value[0].address;
  if (json.from?.address) return json.from.address;
  if (json.From) return json.From;
  const headerFrom = getHeaderValue(json, 'From');
  if (headerFrom) return headerFrom;
  return 'Unknown sender';
}

function getSubject(json) {
  if (typeof json.subject === 'string' && json.subject.trim()) return json.subject;
  if (json.Subject) return json.Subject;
  const headerSubject = getHeaderValue(json, 'Subject');
  if (headerSubject) return headerSubject;
  return '(no subject)';
}

// Count how many unread emails in this batch share the same Gmail thread,
// so multi-message threads can be flagged instead of listed as separate, unrelated emails
const threadCounts = {};
for (const item of items) {
  const threadId = item.json.threadId;
  if (threadId) threadCounts[threadId] = (threadCounts[threadId] || 0) + 1;
}

const lines = items.map((item, i) => {
  const from = getFrom(item.json);
  const subject = getSubject(item.json);
  const snippet = (item.json.snippet || '').replace(/\n/g, ' ').slice(0, 300);
  const category = getCategory(item.json);
  const threadId = item.json.threadId;
  const threadCount = threadId ? (threadCounts[threadId] || 1) : 1;
  const threadTag = threadCount > 1 ? ` [Thread: ${threadCount} unread messages in this conversation]` : '';
  return `${i + 1}. [Category: ${category}]${threadTag} From: ${from}\n   Subject: ${subject}\n   Preview: ${snippet}`;
});

return [{ json: { emailBlock: lines.join('\n\n'), hasEmails: true, count: items.length } }];

// Pull the plain text summary out of Claude's response
const response = $input.first().json;
const summaryText = response.content?.[0]?.text || 'No summary returned.';
return [{ json: { summaryText } }];
